# Root overview: make the P0 capability expansion visible without duplicating the API reference.
readme = Path('README.md')
text = readme.read_text()
anchor = 'They do not perform general JavaScript truthiness or unrestricted coercion.\n'
addition = '''They do not perform general JavaScript truthiness or unrestricted coercion.

### State-aware validation and collection steps

Valchecker exposes strict comparisons, exact length and inclusion checks, primitive narrowing, nullish narrowing, Unicode normalization, and array mapping only when the current output supports them:

```ts
const status = v.unknown()
	.isOneOf(['draft', 'published'] as const)

const quantity = v.number()
	.isGreaterThan(0)
	.isSafeInteger()

const labels = v.array(v.string())
	.toMapped(value => value.toLowerCase())
```

`isEqualTo()` and `isOneOf()` use `Object.is` semantics and narrow the successful output type. `isDefined()`, `isNonNull()`, and `isNonNullish()` disappear from the fluent API once the excluded values are no longer possible.
'''
if '### State-aware validation and collection steps' not in text:
	text = text.replace(anchor, addition)
readme.write_text(text)

